import { useState } from "react";

const toppings = [
  { emoji: "🍄", price: 40 },
  { emoji: "🧀", price: 45 },
  { emoji: "🌽", price: 30 },
  { emoji: "🍍", price: 35 },
  { emoji: "🧅", price: 20 },
  { emoji: "🌶️", price: 25 },
];

const BASE_PRICE = 299;

export default function PizzaBuilder() {
  const [selected, setSelected] = useState(toppings[0]);
  const [pizza, setPizza] = useState([]);

  function handleSelectTopping(topping) {
    setSelected(topping);
  }

  function handlePizzaClick(event) {
    const rect = event.currentTarget.getBoundingClientRect();

    const topping = {
      emoji: selected.emoji,
      price: selected.price,
      x: event.clientX - rect.left,
      y: event.clientY - rect.top,
    };

    setPizza([...pizza, topping]);
  }

  function calculateTotal() {
    let total = BASE_PRICE;

    for (const topping of pizza) {
      total += topping.price;
    }

    return total;
  }

  return (
    <main>
      <h1>🍕 Pizza Builder</h1>

      <h2>
        <strong>Total:</strong> ₹{calculateTotal()}
      </h2>

      <p>
        {toppings.map(function (topping) {
          return (
            <button
              key={topping.emoji}
              onClick={() => handleSelectTopping(topping)}
              disabled={selected === topping}
            >
              {topping.emoji}
            </button>
          );
        })}
      </p>

      <figure
        onClick={handlePizzaClick}
        style={{
          position: "relative",
        }}
      >
        <img
          src="https://www.shutterstock.com/image-illustration/pizza-no-topping-260nw-2685328587.jpg"
          alt="Pizza"
          width="350"
        />

        {pizza.map(function (topping, index) {
          return (
            <span
              key={index}
              style={{
                position: "absolute",
                left: topping.x,
                top: topping.y,
                // transform: "translate(-50%, -50%)",
                fontSize: "2rem",
              }}
            >
              {topping.emoji}
            </span>
          );
        })}
      </figure>
    </main>
  );
}
